function Avatar() {
  return <img src="/avatar.png" alt="User avatar" />;
}

function UserCard() {
  return (
    <div className="card">
      <Avatar />
      <p>Jane Doe</p>
    </div>
  );
}

function Card({ img, name, price }) {
  return (
    <div className="card">
      <img src={img} alt={name} />
      <h3>{name}</h3>
      <p>${price}</p>
    </div>
  );
}

function ProductList({ products }) {
  return (
    <div className="grid">
      {products.map(p => (
        <Card key={p.id} img={p.img} name={p.name} price={p.price} />
      ))}
    </div>
  );
}

function App() {
  return (
    <>
      <Navbar />
      <Main />
      <Footer />
    </>
  );
}

function Main() {
  const products = useProducts(); // data layer (covered later)
  return (
    <main>
      <ProductList products={products} />
      <Sidebar />
    </main>
  );
}

function ProductList({ products }) {
  return (
    <div className="grid">
      {products.map(p => <Card key={p.id} {...p} />)}
    </div>
  );
}

function Icon({ name }) {
  return <span className={`icon icon-${name}`} />;
}

function Toolbar() {
  return (
    <div>
      <Icon name="save" />
      <Icon name="copy" />
      <Icon name="delete" />
    </div>
  );
}

// BAD — Inner is re-created on every render of Outer
function Outer() {
  function Inner() {       // ← defined inside Outer
    return <p>Hello</p>;
  }
  return <Inner />;
}

// GOOD — Inner is defined at module scope
function Inner() {
  return <p>Hello</p>;
}

function Outer() {
  return <Inner />;
}

function Panel({ title, children }) {
  return (
    <section className="panel">
      <h2>{title}</h2>
      <div className="panel-body">{children}</div>
    </section>
  );
}

// Usage — anything inside <Panel>...</Panel> becomes children
function Dashboard() {
  return (
    <Panel title="Summary">
      <p>Revenue: $12,400</p>
      <p>Users: 340</p>
    </Panel>
  );
}

function Layout({ header, sidebar, main }) {
  return (
    <div className="layout">
      <header>{header}</header>
      <aside>{sidebar}</aside>
      <main>{main}</main>
    </div>
  );
}

function App() {
  return (
    <Layout
      header={<Navbar />}
      sidebar={<FilterPanel />}
      main={<ProductList />}
    />
  );
}

