// App.jsx
import ProductList from './ProductList';

export default function App() {
  const products = [
    { id: 1, img: '/a.jpg', name: 'Widget', price: 9.99 },
    { id: 2, img: '/b.jpg', name: 'Gadget', price: 14.99 },
  ];
  return <ProductList products={products} />;
}

function Page({ user, isAdmin }) {
  return (
    <div>
      <Navbar user={user} />
      {isAdmin && <AdminToolbar />}
      <Content />
    </div>
  );
}

function PrimaryButton({ className, ...rest }) {
  return (
    <button
      className={`btn btn-primary ${className ?? ''}`}
      {...rest}
    />
  );
}

function Tag({ label }) {
  return <span className="tag">{label}</span>;
}

function TagList({ tags }) {
  return (
    <div className="tags">
      {tags.map(t => <Tag key={t} label={t} />)}
    </div>
  );
}

function PostHeader({ title, author, date }) {
  return (
    <header>
      <h1>{title}</h1>
      <p>By {author} on {date}</p>
    </header>
  );
}

function PostBody({ content }) {
  return <article>{content}</article>;
}

function PostPage({ post }) {
  return (
    <main>
      <PostHeader title={post.title} author={post.author} date={post.date} />
      <TagList tags={post.tags} />
      <PostBody content={post.content} />
    </main>
  );
}

function CommentList({ comments }) {
  if (comments.length === 0) {
    return <p>No comments yet.</p>;
  }
  return (
    <ul>
      {comments.map(c => (
        <li key={c.id}>
          <Comment author={c.author} text={c.text} />
        </li>
      ))}
    </ul>
  );
}

function DataFetcher({ url, render }) {
  const [data, setData] = React.useState(null);

  React.useEffect(() => {
    fetch(url).then(r => r.json()).then(setData);
  }, [url]);

  if (!data) return <p>Loading…</p>;
  return render(data);
}

// Usage
<DataFetcher
  url="/api/products"
  render={products => (
    <ProductList products={products} />
  )}
/>

function withLogger(WrappedComponent) {
  return function LoggedComponent(props) {
    console.log('Rendering', WrappedComponent.displayName, props);
    return <WrappedComponent {...props} />;
  };
}

const LoggedProductList = withLogger(ProductList);
